const ws = new WebSocket('ws://127.0.0.1:8766');
const subscriptionRecord = new Set();
const backoffSchedule = [1000, 2000, 5000, 10000];
let backoffIndex = 0;
let suppressReconnect = false;
let reconnectTimer = null;
let lastBandConnected = false;

function subscribe(signal) {
  subscriptionRecord.add(signal);
  ws.send(JSON.stringify({ command: 'subscribe', signal }));
}

function connect() {
  const socket = new WebSocket('ws://127.0.0.1:8766');

  socket.onopen = () => {
    backoffIndex = 0;
    socket.send(JSON.stringify({ command: 'get_status' }));
    subscriptionRecord.forEach(signal => socket.send(JSON.stringify({ command: 'subscribe', signal })));
  };

  socket.onmessage = (event) => {
    const msg = JSON.parse(event.data);
    if (msg.type === 'status') {
      const bandConnected = Boolean(msg.data.device.firmware && msg.data.device.serial_number);
      const hand = bandConnected ? msg.data.device.hand : 'None';
      updateConnectionLabel(bandConnected, hand);
      if (bandConnected && !lastBandConnected) {
        // Band just reconnected — replay subscriptions (FR-018a)
        subscriptionRecord.forEach(signal => socket.send(JSON.stringify({ command: 'subscribe', signal })));
      }
      lastBandConnected = bandConnected;
    }
    if (msg.type === 'error' && msg.data.error === 'client_already_connected') {
      suppressReconnect = true;
      showAlreadyInUseMessage();
    }
    if (msg.type === 'gesture') handleGesture(msg.data);
    if (msg.type === 'pressure') handlePressure(msg.data);
    if (msg.type === 'navigation') handleNavigation(msg.data);
  };

  socket.onclose = () => {
    if (suppressReconnect) return;
    showReconnecting();
    const delay = backoffSchedule[Math.min(backoffIndex, backoffSchedule.length - 1)];
    backoffIndex = Math.min(backoffIndex + 1, backoffSchedule.length - 1);
    reconnectTimer = setTimeout(connect, delay);
  };
}

